using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithSameItems()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithVariousItems_CalculatesCorrectTotal(
        string scenario, List<OrderItem> items, decimal expectedTotal)
    {
        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {scenario}");
    }

    public static IEnumerable<(string scenario, List<OrderItem> items, decimal expectedTotal)> TotalCalculationData =>
    [
        ("single item", CreateItems(("Widget", 10m, 2)), 20m),
        ("multiple items", CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 3)), 35m),
        ("single unit", CreateItems(("Widget", 25.50m, 1)), 25.50m),
        ("zero price", CreateItems(("Freebie", 0m, 5)), 0m),
    ];

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder — validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var found = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        Assert.IsNull(_service.GetOrder("does-not-exist"));
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreations_ReturnsCorrectOrder()
    {
        // Arrange
        var order1 = _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        var order2 = _service.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));

        // Act & Assert
        var found = _service.GetOrder(order2.Id);
        Assert.IsNotNull(found);
        Assert.AreEqual("cust-2", found.CustomerId);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.IsNotNull(result);
        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OneMatchingOrder_ReturnsSingleOrder()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateItems(("Widget", 10m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("Gadget", 5m, 1)));

        // Act
        var result = _service.GetOrdersByCustomer("cust-1");

        // Assert
        var single = Assert.ContainsSingle(result);
        Assert.AreEqual("cust-1", single.CustomerId);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleMatchingOrders_ReturnsAll()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        // Act
        var result = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, result);
    }

    #endregion
}

